query ProductRelationshipProductOptionsRead($productId: ID!) {
  product(id: $productId) {
    id
    title
    handle
    status
    options {
      id
      name
      position
      values
      optionValues {
        id
        name
        hasVariants
      }
    }
    variants(first: 10) {
      nodes {
        id
        title
        selectedOptions {
          name
          value
        }
      }
    }
  }
}

query ProductOptionsHydrateNodes($ids: [ID!]!) {
  nodes(ids: $ids) {
    ... on Product {
      id
      title
      handle
      status
      options {
        id
        name
        position
        optionValues {
          id
          name
          hasVariants
        }
      }
      variants(first: 100) {
        nodes {
          id
          title
          selectedOptions {
            name
            value
          }
        }
      }
    }
  }
}

query MediaProductHydrate($id: ID!) {
  product(id: $id) {
    id
    title
    handle
    status
    media(first: 50) {
      nodes {
        id
        alt
        mediaContentType
        status
        preview { image { url width height } }
        ... on MediaImage { image { url width height } }
      }
    }
    variants(first: 50) {
      nodes {
        id
        title
        media(first: 10) { nodes { id } }
      }
    }
  }
}

